int main_with_test_input() {
    std::string sentence;
    std::getline(std::cin, sentence);

    std::stringstream ss(sentence);
    std::string word;
    int wordCount = 0;

    while (ss >> word) {
        wordCount++;
    }

    std::cout << "Total number of words: " << wordCount << std::endl;
    return 0;
}

int main() {
    return main_with_test_input();
}
